+        let artifact = EmergencyGrantArtifact::new_signed(
+            "req-2",
+            "ext-b",
+            Capability::FsWrite,
+            "emergency write".to_string(),
+            "admin".to_string(),
+            5000,
+            3,
+            false,
+            true,
+            100,
